import{_ as a,c as t,o as i,ag as o}from"./chunks/framework.C_tke1Yp.js";const u=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md"}'),l={name:"roadmap.md"};function r(n,e,s,p,d,m){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>This project brings together experience and capabilities from work in the Earth Observation field. It will evolve iteratively, shaped by ongoing development and community interactions.</p><p>We welcome feedback and inputs through issues in respective components. If you are unsure where to create an issue, use the <a href="https://github.com/eodash/eodash/issues" target="_blank" rel="noreferrer">eodash issue board</a>.</p><p>To support discussion, here are key roadmap areas and topics.</p><ul><li>eodash <ul><li>Extend support for generic STAC catalogs</li><li>Develop eodash STAC catalog extension</li><li>Expand example (template) repositories for other frameworks</li><li>Implement support of flat styles for serverless datasets (COG and GeoJSON)</li><li>Explore supporting cloud optimized vector formats</li><li>Implement chart rendering of data based on <a href="https://vega.github.io/vega/" target="_blank" rel="noreferrer">VEGA chart definition language</a></li><li>Document how to implement a custom widget (as part of eodash instance template)</li></ul></li><li>catalog <ul><li>Introduce a plugin system</li><li>Document how to create custom plugins</li><li>Improve performance for very large collections</li><li>Evaluat a potential switch to a different base library</li></ul></li><li>storytelling <ul><li>Allow importing map state based on passed STAC item (and state modifiers)</li><li>Allow importing of chart state based on passed STAC item (and state modifiers)</li><li>Integrate VEGA chart definition rendering component</li><li>Improve documentation</li></ul></li><li>documentation <ul><li>Expand usage guides and examples</li><li>Add links to open example instances</li></ul></li><li>other <ul><li>Initiate the process of becoming an OSGeo Community Project</li><li>Create a library or helper UI to simplify creating flat styles (extended by eox-forms)</li><li>Implement (or wrap) VEGA chart definition rendering component</li><li>Add example images and animations to the documentation</li></ul></li></ul>',5)])])}const h=a(l,[["render",r]]);export{u as __pageData,h as default};
